#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<19,stdin),p1==p2)?EOF:*p1++)
#define putchar(a) (*O++=(a))
char buf[1<<23],*p1=buf,*p2=buf,obuf[1<<25],*O=obuf;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
const int N=2e6+10;int t0[N],t1[N],pp,Q,n,del[N],P[N],tem[N],val[N],num[2];bool typ[N];
inline void add0(int p,const int &w){while(p<=pp)t0[p]+=w,p+=(p&-p);}
inline void add1(int p,const int &w){p=pp-p+1;while(p<=pp)t1[p]+=w,p+=(p&-p);}
inline int qry0(int p){int res(0);while(p)res+=t0[p],p^=(p&-p);return res;}
inline int qry1(int p){p=pp-p+1;int res(0);while(p)res+=t1[p],p^=(p&-p);return res;}
inline int fnd(const int &k){int l(1),r(pp),m;while(l<=r)P[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
int main()
{
	Q=read();
	rep(1,Q,i){read()==1?typ[i]=read(),P[++pp]=tem[i]=read(),val[i]=read():del[i]=read();}
	std::sort(P+1,P+pp+1);pp=std::unique(P+1,P+pp+1)-P-1; 
	rep(1,Q,i)
	{
		if(del[i]){typ[del[i]]?add1(tem[del[i]],-val[del[i]]),--num[1]:(add0(tem[del[i]],-val[del[i]]),--num[0]);}
		else{tem[i]=fnd(tem[i]);typ[i]?add1(tem[i],val[i]),++num[1]:(add0(tem[i],val[i]),++num[0]);}
		if(!num[0]||!num[1]){putchar('P');putchar('e');putchar('a');putchar('c');putchar('e');putchar('\n');continue;}
		int l(1),r(pp),restem(0),resval(0),mid(0);
		while(l<=r)
		{
			mid=(l+r)>>1;const int &t0=qry0(mid),&t1=qry1(mid);
			if(t0<t1){l=mid+1;restem=mid;resval=t0;} else r=mid-1;
		}
		if(restem==pp){print(P[1]);putchar(' ');print(resval<<1);putchar('\n');continue;}
		const int &t1=qry1(restem+1);
		if(t1<resval)
		{
			if(!resval){putchar('P');putchar('e');putchar('a');putchar('c');putchar('e');putchar('\n');continue;}
			print(P[restem]),putchar(' '),print(resval<<1),putchar('\n');
		}
		else
		{
			//大于P[restem+1]的第一个火系战士的温度
			if(!t1){putchar('P');putchar('e');putchar('a');putchar('c');putchar('e');putchar('\n');continue;}
			int l=restem+1,r=pp,mid;
			while(l<=r)qry1(mid=(l+r)>>1)==t1?l=mid+1:r=mid-1;
			print(P[l-1]);putchar(' ');print(t1<<1);putchar('\n');
		}
		
//		resval<=t0?print(P[restem-1]),putchar(' '),print(t0<<1):(print(P[restem]),putchar(' '),print(resval<<1));putchar('\n');
	}
	fwrite(obuf,O-obuf,1,stdout);
	
}
